import json

import yaml

from prompty.model import MemoryCategory


def test_load_json_memorycategory():
    json_data = r"""
    {
      "kind": "semantic",
      "label": "project-fact"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = MemoryCategory.load(data)
    assert instance is not None
    assert instance.kind == "semantic"
    assert instance.label == "project-fact"


def test_load_yaml_memorycategory():
    yaml_data = r"""
    kind: semantic
    label: project-fact

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
    instance = MemoryCategory.load(data)
    assert instance is not None
    assert instance.kind == "semantic"
    assert instance.label == "project-fact"


def test_roundtrip_json_memorycategory():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "kind": "semantic",
      "label": "project-fact"
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = MemoryCategory.load(original_data)
    saved_data = instance.save()
    reloaded = MemoryCategory.load(saved_data)
    assert reloaded is not None
    assert reloaded.kind == "semantic"
    assert reloaded.label == "project-fact"


